import{_ as t,c as i,a1 as h,o as a}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Xây Dựng Phòng Thí Nghiệm","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/0-core-knowledge/1-Lab-Building.md","filePath":"vi/categories/ethical-hacking-labs/0-core-knowledge/1-Lab-Building.md"}'),o={name:"vi/categories/ethical-hacking-labs/0-core-knowledge/1-Lab-Building.md"};function c(l,n,r,e,u,g){return a(),i("div",null,n[0]||(n[0]=[h('<h1 id="xay-dung-phong-thi-nghiem" tabindex="-1">Xây Dựng Phòng Thí Nghiệm <a class="header-anchor" href="#xay-dung-phong-thi-nghiem" aria-label="Permalink to &quot;Xây Dựng Phòng Thí Nghiệm&quot;">​</a></h1><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Windows 10, macOS hoặc bất kỳ bản phân phối Linux nào <ul><li>Ít nhất 8 GB RAM (khuyến nghị 16GB)</li></ul></li></ul><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Hiểu cách máy ảo hoạt động</li><li>Học cách tạo môi trường ảo cơ bản cho mục đích kiểm thử xâm nhập</li></ul><h1 id="may-ao-vm-la-gi" tabindex="-1">Máy ảo (VM) là gì? <a class="header-anchor" href="#may-ao-vm-la-gi" aria-label="Permalink to &quot;Máy ảo (VM) là gì?&quot;">​</a></h1><p>Để đơn giản, hãy nghĩ về máy ảo (VM) như một &quot;máy tính làm từ phần mềm&quot; mà bạn có thể sử dụng để chạy bất kỳ phần mềm nào bạn sẽ chạy trên một máy tính vật lý thực. Giống như máy vật lý, máy ảo có hệ điều hành riêng (Windows, Linux, v.v.), lưu trữ, mạng, cài đặt cấu hình và phần mềm, và nó hoàn toàn được cách ly khỏi các máy ảo khác chạy trên máy chủ đó.</p><p><img src="https://miro.medium.com/max/937/1*QgshMdPQ7ZzK1hRbv1ncPQ.jpeg" alt="vm"></p><p><strong>Lợi ích bảo mật</strong> — Vì máy ảo chạy trên nhiều hệ điều hành, sử dụng hệ điều hành khách trên VM cho phép bạn chạy các ứng dụng có độ bảo mật đáng ngờ và bảo vệ hệ điều hành chủ của bạn. Máy ảo cũng cho phép pháp y bảo mật tốt hơn, kiểm thử xâm nhập và thường được sử dụng để nghiên cứu virus máy tính một cách an toàn, cách ly virus để tránh rủi ro cho máy tính chủ.</p><h3 id="hypervisor" tabindex="-1">Hypervisor <a class="header-anchor" href="#hypervisor" aria-label="Permalink to &quot;Hypervisor&quot;">​</a></h3><p>Có hai loại hypervisor chính, được gọi là <strong>&quot;Loại 1&quot; (hoặc &quot;bare metal&quot;)</strong> và <strong>&quot;Loại 2&quot; (hoặc &quot;hosted&quot;)</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0143eb15cf424c87ae823109d73df9ebe3faebec/hyper.png" alt="hypervisors"></p><ul><li><strong>Hypervisor Loại 1</strong> hoạt động như một hệ điều hành nhẹ và chạy trực tiếp trên phần cứng của máy chủ.</li><li><strong>Hypervisor Loại 2</strong> chạy như một lớp phần mềm trên hệ điều hành, giống như các chương trình máy tính khác.</li></ul><h1 id="_1-cai-đat-virtualbox" tabindex="-1">1. Cài đặt VirtualBox <a class="header-anchor" href="#_1-cai-đat-virtualbox" aria-label="Permalink to &quot;1. Cài đặt VirtualBox&quot;">​</a></h1><ul><li><strong>Hướng dẫn này sử dụng <a href="https://www.virtualbox.org" target="_blank" rel="noreferrer">Oracle VM VirtualBox</a>, hypervisor hosted miễn phí và mã nguồn mở phổ biến nhất cho ảo hóa x86, được phát triển bởi Oracle.</strong></li><li>Có các tùy chọn khác từ các nhà cung cấp khác nhau để đạt kết quả tương tự: <ul><li><a href="https://www.vmware.com/products/workstation-player.html" target="_blank" rel="noreferrer">VMware Player cho Windows (dùng thử 30 ngày)</a></li><li><a href="https://www.vmware.com/products/fusion.html" target="_blank" rel="noreferrer">VMware Fusion cho macOS (dùng thử 30 ngày)</a></li><li><a href="https://docs.microsoft.com/en-us/virtualization/hyper-v-on-windows/about/" target="_blank" rel="noreferrer">Windows Hyper-V</a></li><li><a href="https://help.ubuntu.com/community/KVM/Installation" target="_blank" rel="noreferrer">Linux KVM</a></li></ul></li></ul><ol><li><strong>Đảm bảo PC của bạn hỗ trợ ảo hóa phần cứng (Windows)</strong><ul><li>Khởi động lại máy tính của bạn</li><li>Ngay khi máy tính đang khởi động từ màn hình đen, nhấn Delete, Esc, F1, F2 hoặc F4. Mỗi nhà sản xuất máy tính sử dụng một phím khác nhau nhưng nó có thể hiển thị một thông báo ngắn khi khởi động cho bạn biết nhấn phím nào. Nếu bạn bỏ lỡ lần đầu, khởi động lại và thử lại. Nhấn phím khoảng hai lần một giây khi máy tính đang khởi động rất hữu ích. Nếu bạn không thể vào BIOS bằng phương pháp này, hãy tham khảo hướng dẫn sử dụng máy tính của bạn.</li><li>Trong cài đặt BIOS, tìm các mục cấu hình liên quan đến CPU. Chúng có thể nằm dưới các tiêu đề Processor, Chipset hoặc Northbridge.</li><li>Bật ảo hóa; cài đặt có thể được gọi là <strong>VT-x, AMD-V, SVM, hoặc Vanderpool</strong>. Bật Intel VT-d hoặc AMD IOMMU nếu các tùy chọn có sẵn.</li><li>Lưu thay đổi và khởi động lại.</li></ul></li></ol><blockquote><p>⚠️ Nếu bạn không thể tìm thấy cài đặt ảo hóa trong BIOS, điều đó có thể có nghĩa là máy tính của bạn không hỗ trợ.</p></blockquote><ol start="2"><li><p><strong>Tải phiên bản mới nhất của Virtual Box</strong></p><ul><li>Truy cập trang web Oracle Virtual Box: <ul><li><a href="https://www.virtualbox.org/wiki/Downloads" target="_blank" rel="noreferrer">https://www.virtualbox.org/wiki/Downloads</a></li></ul></li><li>Chọn hệ điều hành hiện tại của bạn và tải trình cài đặt</li><li><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/944dad38ad3bfc556600c6ca3e08ec83cabd54e5/vbox1.png" alt="v"></li><li>Ngoài ra, cuộn xuống trên cùng trang và tải <strong>VirtualBox Extension Pack</strong>. Phần mở rộng này sẽ cho phép các tính năng VirtualBox như hỗ trợ USB, mã hóa đĩa ảo, v.v.</li><li><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/944dad38ad3bfc556600c6ca3e08ec83cabd54e5/vbox2.png" alt="v2"></li></ul></li><li><p><strong>Cài đặt Virtual Box và Extension Pack</strong></p><ul><li>Không có cấu hình đặc biệt nào trong quá trình cài đặt <strong>Virtual Box</strong>, chỉ cần click và cài đặt.</li><li>Khi cài đặt xong, cài đặt <strong>Extension Pack</strong> bằng cách nhấp đúp vào nó; Phần mở rộng tệp là <code>.vbox-extpack</code>. Đừng lo lắng về các cảnh báo.</li></ul></li></ol><h2 id="cau-hinh-nat-cua-virtualbox" tabindex="-1">Cấu hình NAT của VirtualBox <a class="header-anchor" href="#cau-hinh-nat-cua-virtualbox" aria-label="Permalink to &quot;Cấu hình NAT của VirtualBox&quot;">​</a></h2><p><em>Các bước tiếp theo sẽ hướng dẫn cách tạo mạng NAT trên VirtualBox. Nói đơn giản, Máy ảo cần một card mạng ảo, để truy cập internet và tách biệt IP Máy chủ (hệ điều hành chính) và IP Khách (VM).</em></p><ol start="4"><li><strong>Khởi chạy VirtualBox và mở panel <code>Preferences</code></strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1b0a358d438d859df17db305753ce41c1826e4b0/pref1.png" alt="pref1"></p><ol start="5"><li><strong>Vào tab <code>Network</code> ở panel bên trái, sau đó nhấn nút <code>green plus button</code> ở bên phải</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1b0a358d438d859df17db305753ce41c1826e4b0/pref2.png" alt="pref2"></p><ol start="6"><li><strong>Theo mặc định, VirtualBox tự động tạo một NatNetwork. Nhấn nút <code>OK</code> và lưu cấu hình này</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1b0a358d438d859df17db305753ce41c1826e4b0/pref3.png" alt="pref3"></p><ol start="7"><li><strong>Phần tiếp theo chúng ta sẽ tải phiên bản Kali Linux mới nhất và khởi động nó trong phần mềm VirtualBox</strong></li></ol><h2 id="gioi-thieu-ve-kali-linux" tabindex="-1">Giới thiệu về Kali Linux <a class="header-anchor" href="#gioi-thieu-ve-kali-linux" aria-label="Permalink to &quot;Giới thiệu về Kali Linux&quot;">​</a></h2><p><img src="https://www.bleepstatic.com/content/hl-images/2019/11/29/kali-header.jpg" alt="kali"></p><blockquote><p>⚠️ Hướng dẫn Kali Linux sẽ được giới thiệu ở module tiếp theo [Linux cho Hacker].md</p></blockquote><p>Kali Linux (trước đây được gọi là BackTrack Linux) là một bản phân phối Linux mã nguồn mở, dựa trên Debian, hướng đến Kiểm thử Xâm nhập nâng cao và Kiểm toán Bảo mật. <a href="https://www.kali.org/docs/introduction/what-is-kali-linux/" target="_blank" rel="noreferrer">[+]</a></p><p>Kali Linux chứa vài trăm công cụ nhắm đến nhiều nhiệm vụ bảo mật thông tin khác nhau, chẳng hạn như:</p><ul><li>Kiểm thử Xâm nhập</li><li>Nghiên cứu Bảo mật</li><li>Pháp y Máy tính</li><li>Kỹ thuật Đảo ngược</li></ul><h2 id="tai-hinh-anh-kali-linux-moi-nhat" tabindex="-1">Tải hình ảnh Kali Linux mới nhất <a class="header-anchor" href="#tai-hinh-anh-kali-linux-moi-nhat" aria-label="Permalink to &quot;Tải hình ảnh Kali Linux mới nhất&quot;">​</a></h2><ol><li><strong>Truy cập trang web Offensive Security:</strong><ul><li><a href="https://www.offensive-security.com/kali-linux-vm-vmware-virtualbox-image-download/" target="_blank" rel="noreferrer">https://www.offensive-security.com/kali-linux-vm-vmware-virtualbox-image-download/</a></li></ul></li><li><strong>Tải hình ảnh VirtualBox của Kali Linux, đảm bảo chọn <code>Virtual Box image (OVA)</code></strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/163a5fcc5653f6c06fb7e63fbf570e3fd9b5c144/kali0.png" alt="kali0"></p><h1 id="_2-cai-đat-kali-linux-tren-virtualbox" tabindex="-1">2. Cài đặt Kali Linux trên VirtualBox <a class="header-anchor" href="#_2-cai-đat-kali-linux-tren-virtualbox" aria-label="Permalink to &quot;2. Cài đặt Kali Linux trên VirtualBox&quot;">​</a></h1><p>Khi bạn đã cài đặt VirtualBox và tải hình ảnh Kali Linux, bạn chỉ cần nhập nó vào VirtualBox để làm cho nó hoạt động.</p><ol><li><strong>Khởi chạy VirtualBox và nhấn nút <code>Import Button</code> ở menu trên cùng</strong></li></ol><p><img src="https://i1.wp.com/itsfoss.com/wp-content/uploads/2019/02/vmbox-import-kali-linux.jpg?w=956&amp;ssl=1" alt="kali1"></p><ol start="2"><li><strong>Tiếp theo, duyệt đến hình ảnh Kali Linux (OVA) bạn vừa tải và chọn để nhập (như bạn có thể thấy trong hình dưới đây).</strong></li></ol><p><img src="https://i2.wp.com/itsfoss.com/wp-content/uploads/2019/02/vmbox-linux-next.jpg?w=954&amp;ssl=1" alt="kali2"></p><ol start="3"><li><strong>Tiếp theo, bạn sẽ thấy cài đặt cho máy ảo sắp được nhập. Bạn có thể tùy chỉnh hoặc không – đó là lựa chọn của bạn dựa trên dung lượng phần cứng.</strong><ul><li>Nếu bạn có máy tính với 8GB RAM và ít nhất 2 lõi, để cài đặt mặc định.</li><li>Nếu máy tính của bạn có 16GB RAM hoặc hơn, tôi khuyến nghị sử dụng 4GB RAM cho Kali Linux, để làm điều đó, cuộn xuống danh sách cấu hình và thay đổi <code>giá trị RAM</code> thành <code>4096</code> MB</li></ul></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9a53e3ba4ca62c777cf59acc53d211b4c187598e/pref4.png" alt="kali3"></p><ol start="4"><li><strong>Bạn sẽ thấy Kali box được liệt kê. Chỉ cần nhấn Start để khởi chạy.</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5f7c4d496d67f429aff72c1c177028f16dc35379/pref5.png" alt="kali4"></p><ol start="5"><li><strong>Nhập thông tin đăng nhập mặc định:</strong> username: <code>kali</code>, password: <code>kali</code>. <ul><li>Mẹo: Trên Linux, bạn có thể thay đổi mật khẩu mặc định của người dùng hiện tại bằng cách nhập <code>passwd</code> trên terminal.</li></ul></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5f7c4d496d67f429aff72c1c177028f16dc35379/kali-log.png" alt="kali5"></p><ol start="6"><li><strong>Hoàn thành!</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/a8f9a9f928ce6aeb71683cf95cb738b5842d0c04/kali-desk.png" alt="kali6"></p><ul><li>⚠️ <strong>Module tiếp theo bạn sẽ học một số kỹ thuật của bản phân phối Kali và cách vận hành trên chính Linux.</strong></li></ul>',51)]))}const p=t(o,[["render",c]]);export{m as __pageData,p as default};
